import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';
import Dashboard from './Dashboard'; // We will create this next
import './App.css';

function App() {
  const [session, setSession] = useState(null);

  useEffect(() => {
    // Check current auth status
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    // Listen for changes (login/logout)
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  return (
    <div className="App">
      {!session ? (
        <div className="auth-container">
          <h2>Clinical Intelligence Login</h2>
          <button onClick={() => supabase.auth.signInWithOAuth({ provider: 'google' })}>
            Sign In with Google to Access Vault
          </button>
          {/* Or add your custom Email/Password form here */}
        </div>
      ) : (
        <Dashboard user={session.user} onLogout={handleLogout} />
      )}
    </div>
  );
}

export default App;
